CREATE OR REPLACE FUNCTION fpb_get_type_desc (as_typecode text) RETURNS varchar AS $body$
DECLARE

    ls_typedesc             varchar(100);

BEGIN
  select  trim(both loan_type_description)
  into STRICT    ls_typedesc
  from    sc_lon_m_rule
  where (loan_type = as_typecode);
  return ls_typedesc;
exception when others then CALL spa_dberror('('||trim(both as_typecode)||')');
END;
$body$
